input.content:
const PROCESSING_FEE = 5;

interface QuoteStep {
  op: "quote";
  items: { type: string }[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => {
    const policyBase = step.items.reduce((sum, item) => {
      if (item.type === "sword") return sum + 100;
      return sum;
    }, 0);
    const firstInsurance = policyBase * 0.1;
    const premium = Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
    return { premium };
  });
  return { results };
};

