import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Edge case: empty policy ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const { results } = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(results).toEqual([{ premium: 5 }]);
  });

  // --- Base premiums for main items (single item, newcomer 0 yrs, first insurance) ---
  // These verify the base price list. Newcomer first insurance adds 10%; +5 fee.
  // To keep early tests focused on the base, we use a customer where modifiers cancel
  // or are explicitly accounted for in the description.

  it("single sword, base premium 100 G → premium with first-insurance 10% + fee = 115 G", () => {
    const { results } = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] },
      ],
    });
    expect(results).toEqual([{ premium: 115 }]);
  });
  it.todo("single amulet, base premium 60 G → premium 71 G (60 +6 first +5 fee)");
  it.todo("single staff, base premium 80 G → premium 93 G (80 +8 first +5 fee)");
  it.todo("single potion, base premium 40 G → premium 49 G (40 +4 first +5 fee)");

  // --- Components: 250 G value / 25 G base premium each ---
  it.todo("single rune, base premium 25 G → premium 32.5 rounded up 33 G (25 +2.5 first +5 fee)");
  it.todo("single moonstone, base premium 25 G → premium 33 G");

  // --- Building block of 3 alike components ---
  it.todo("2 runes → 50 G base premium");
  it.todo("3 runes → 60 G base premium (block applies)");
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium (one block of 3 = 60, plus 4 singles = 100)");

  // --- 'Alike' = same type ---
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // --- Premium modifiers in isolation ---
  it.todo("cursed sword (newcomer, ench 3): 100 base +50 curse +10 first +5 fee = 165 G");
  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies (+30%)");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("customer with exactly 2 years → 20% loyalty discount applies");

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword (base 100) + plain amulet (base 60): policy base 160, curse adds 50 (50% of cursed item base) → 210 before further modifiers and fee");

  // --- Rounding ---
  it.todo("premium calculation yielding 197.5 G → 198 G (rounded up)");
  it.todo("payout calculation yielding 350.5 G → 350 G (rounded down)");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("damage to a rune (value 250), damage 200 → payout 100 (full minus 100 deductible)");

  // --- Claim: enchantment threshold ---
  it.todo("steel sword, ench 9, damage 1000 → payout 400 (50% then deductible: 500-100)");
  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon full reimburse, then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (50% wins, then deductible)");
  it.todo("dragon-material sword, ench 8, damage 1000 → payout 400 (high-ench clause then deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");

  // --- Claim: cap ---
  it.todo("policy covers sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword (value 1000, premium 165) → cap 2000 (based on unmodified value)");
  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 (block affects premium only, not sum)");
  it.todo("two swords → insurance sum 2000, cap 4000");

  // --- Claim: cap exhaustion across successive claims ---
  it.todo("sword (sum 1000, cap 2000); claim 1500 → payout 1400, remainingCap 600");
  it.todo("then second claim 1500 → payout 600, remainingCap 0 (reduced to remaining cap)");

  // --- Multiple items of same type in damages ---
  it.todo("two swords insured; damages has two sword entries → each is a separate damage with own deductible");
  it.todo("damages has more entries of a type than insured (two sword damages, one sword) → CLI non-zero exit, claim rejected");

  // --- Edge cases (CLI errors) ---
  it.todo("quote with unknown item type (broomstick) → CLI non-zero exit, error to stderr, no results on stdout");
  it.todo("claim references item not in policy (amulet damaged, only sword insured) → CLI non-zero exit, error to stderr");
  it.todo("claim damage with amount -200 → CLI non-zero exit, error to stderr");

  // --- Integration examples ---
  it.todo("newcomer cursed sword (steel ench 3): premium 165 G");
  it.todo("long-standing (3 yrs) second contract, cursed sword (steel ench 7): premium 160 G");

  // --- CLI end-to-end (schema example) ---
  it.todo("CLI: scenario with quote + claim returns results array of matching length and shape");
});

