const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

interface QuoteStep {
  op: "quote";
  items: { type: string }[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const priceQuote = (items: { type: string }[]): { premium: number } => {
  const policyBase = items.reduce(
    (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
    0,
  );
  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
  const premium = Math.ceil(
    policyBase + firstInsuranceSurcharge + PROCESSING_FEE,
  );
  return { premium };
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => priceQuote(step.items));
  return { results };
};

