const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

interface QuoteStep {
  op: "quote";
  items: { type: string }[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BASE = 25;
const BLOCK_SIZE = 3;
const BLOCK_BASE = 60;

const componentBase = (count: number): number => {
  const blocks = Math.floor(count / BLOCK_SIZE);
  const singles = count % BLOCK_SIZE;
  return blocks * BLOCK_BASE + singles * COMPONENT_BASE;
};

const baseForType = (type: string, count: number): number =>
  COMPONENT_TYPES.has(type)
    ? componentBase(count)
    : (BASE_PREMIUMS[type] ?? 0) * count;

const countByType = (items: { type: string }[]): Map<string, number> =>
  items.reduce(
    (counts, item) =>
      counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
    new Map<string, number>(),
  );

const baseForItems = (items: { type: string }[]): number => {
  let total = 0;
  for (const [type, count] of countByType(items)) {
    total += baseForType(type, count);
  }
  return total;
};

const priceQuote = (items: { type: string }[]): { premium: number } => {
  const policyBase = baseForItems(items);
  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
  const premium = Math.ceil(
    policyBase + firstInsuranceSurcharge + PROCESSING_FEE,
  );
  return { premium };
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => priceQuote(step.items));
  return { results };
};

