const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

interface Item {
  type: string;
  cursed?: boolean;
}

const CURSE_RATE = 0.5;

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BASE = 25;
const BLOCK_SIZE = 3;
const BLOCK_BASE = 60;

const componentBase = (count: number): number =>
  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;

const unitBase = (type: string): number =>
  COMPONENT_TYPES.has(type) ? COMPONENT_BASE : (BASE_PREMIUMS[type] ?? 0);

const baseForType = (type: string, count: number): number =>
  COMPONENT_TYPES.has(type)
    ? componentBase(count)
    : unitBase(type) * count;

const countByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (counts, item) =>
      counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
    new Map<string, number>(),
  );

const baseForItems = (items: Item[]): number =>
  [...countByType(items)].reduce(
    (total, [type, count]) => total + baseForType(type, count),
    0,
  );

const itemBase = (item: Item): number => unitBase(item.type);

const itemSurcharges = (item: Item): number =>
  (item.cursed ? CURSE_RATE * itemBase(item) : 0);

const priceQuote = (items: Item[]): { premium: number } => {
  const policyBase = baseForItems(items);
  const surcharges = items.reduce((sum, item) => sum + itemSurcharges(item), 0);
  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
  const premium = Math.ceil(
    policyBase + surcharges + firstInsuranceSurcharge + PROCESSING_FEE,
  );
  return { premium };
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => priceQuote(step.items));
  return { results };
};

