const DEDUCTIBLE = 100;
const CAP_MULTIPLIER = 2;

const INSURANCE_VALUES: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
};
const COMPONENT_INSURANCE_VALUE = 250;

const insuranceValue = (type: string): number =>
  COMPONENT_TYPES.has(type) ? COMPONENT_INSURANCE_VALUE : (INSURANCE_VALUES[type] ?? 0);

const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + insuranceValue(item.type), 0);

const damagePayout = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE);

const processClaim = (
  step: ClaimStep,
  steps: Step[],
): { payout: number; remainingCap: number } => {
  const policyStep = steps[step.policy] as QuoteStep;
  const cap = insuranceSum(policyStep.items) * CAP_MULTIPLIER;
  const desired = step.incident.damages.reduce(
    (sum, damage) => sum + damagePayout(damage),
    0,
  );
  const payout = Math.floor(Math.min(desired, cap));
  return { payout, remainingCap: cap - payout };
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) =>
    step.op === "quote"
      ? priceQuote(step.items, scenario.customer)
      : processClaim(step, scenario.steps),
  );
  return { results };
};

