94	  unitBase(item.type) * surchargeRate(item);
95	
96	const firstInsuranceSurcharge = (policyBase: number): number =>
97	  policyBase * FIRST_INSURANCE_RATE;
98	
99	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
100	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? policyBase * LOYALTY_RATE : 0;
101	
102	const priceQuote = (items: Item[], customer: Customer): { premium: number } => {
103	  const policyBase = baseForItems(items);
104	  const surcharges = items.reduce((sum, item) => sum + itemSurcharges(item), 0);
105	  const premium = Math.ceil(
106	    policyBase +
107	      surcharges +
108	      firstInsuranceSurcharge(policyBase) -
109	      loyaltyDiscount(policyBase, customer) +
110	      PROCESSING_FEE,
111	  );
112	  return { premium };
113	};
114	
115	const DEDUCTIBLE = 100;
116	const CAP_MULTIPLIER = 2;
117	const HIGH_ENCHANTMENT_REIMBURSE_THRESHOLD = 8;
118	const REIMBURSE_RATE = 0.5;
119	
120	const INSURANCE_VALUES: Record<string, number> = {
121	  sword: 1000,
122	  amulet: 600,
123	  staff: 800,
124	  potion: 400,
125	};
126	const COMPONENT_INSURANCE_VALUE = 250;
127	
128	const insuranceValue = (type: string): number =>
129	  lookupByType(type, COMPONENT_INSURANCE_VALUE, INSURANCE_VALUES);
130	
131	const insuranceSum = (items: Item[]): number =>
132	  items.reduce((sum, item) => sum + insuranceValue(item.type), 0);
133	
134	const reimbursableAmount = (damage: Damage, item: Item | undefined): number =>
135	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSE_THRESHOLD
136	    ? damage.amount * REIMBURSE_RATE
137	    : damage.amount;
138	
139	const damagePayout = (damage: Damage, items: Item[]): number => {
140	  const item = items.find((candidate) => candidate.type === damage.itemType);
141	  return Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
142	};
143	
144	const processClaim = (
145	  step: ClaimStep,
146	  steps: Step[],
147	): { payout: number; remainingCap: number } => {
148	  const policyStep = steps[step.policy] as QuoteStep;
149	  const cap = insuranceSum(policyStep.items) * CAP_MULTIPLIER;
150	  const desired = step.incident.damages.reduce(
151	    (sum, damage) => sum + damagePayout(damage, policyStep.items),
152	    0,
153	  );
154	  const payout = Math.floor(Math.min(desired, cap));
155	  return { payout, remainingCap: cap - payout };
156	};
157	
158	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
159	  const results = scenario.steps.map((step) =>
160	    step.op === "quote"
161	      ? priceQuote(step.items, scenario.customer)
162	      : processClaim(step, scenario.steps),
163	  );
164	  return { results };
165	};

