  step: ClaimStep,
  steps: Step[],
  remainingCapByPolicy: Map<number, number>,
): { payout: number; remainingCap: number } => {
  const policyStep = steps[step.policy] as QuoteStep;
  const remaining =
    remainingCapByPolicy.get(step.policy) ??
    insuranceSum(policyStep.items) * CAP_MULTIPLIER;
  const desired = step.incident.damages.reduce(
    (sum, damage) => sum + damagePayout(damage, policyStep.items),
    0,
  );
  const payout = Math.floor(Math.min(desired, remaining));
  const remainingCap = remaining - payout;
  remainingCapByPolicy.set(step.policy, remainingCap);
  return { payout, remainingCap };
};

